// ============================================================
// SecurePreferencesManager - Encrypted SharedPreferences wrapper
// ============================================================
class SecurePreferencesManager(context: Context) {

    private val masterKey = MasterKey.Builder(context)
        .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
        .build()

    private val sharedPreferences: SharedPreferences = EncryptedSharedPreferences.create(
        context,
        "secure_biometric_prefs",
        masterKey,
        EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
        EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
    )

    companion object {
        private const val KEY_AUTHENTICATED = "is_authenticated"
        private const val KEY_BIOMETRIC_ENABLED = "biometric_enabled"
        private const val KEY_USER_TOKEN = "user_session_token"
        private const val KEY_PASSWORD_HASH = "password_hash"
    }

    fun setAuthenticated(authenticated: Boolean) {
        sharedPreferences.edit().putBoolean(KEY_AUTHENTICATED, authenticated).apply()
    }

    fun isAuthenticated(): Boolean {
        return sharedPreferences.getBoolean(KEY_AUTHENTICATED, false)
    }

    fun setBiometricEnabled(enabled: Boolean) {
        sharedPreferences.edit().putBoolean(KEY_BIOMETRIC_ENABLED, enabled).apply()
    }

    fun isBiometricEnabled(): Boolean {
        return sharedPreferences.getBoolean(KEY_BIOMETRIC_ENABLED, false)
    }

    fun setSessionToken(token: String) {
        sharedPreferences.edit().putString(KEY_USER_TOKEN, token).apply()
    }

    fun getSessionToken(): String? {
        return sharedPreferences.getString(KEY_USER_TOKEN, null)
    }

    fun setPasswordHash(hash: String) {
        sharedPreferences.edit().putString(KEY_PASSWORD_HASH, hash).apply()
    }

    fun getPasswordHash(): String? {
        return sharedPreferences.getString(KEY_PASSWORD_HASH, null)
    }

    fun clearAll() {
        sharedPreferences.edit().clear().apply()
    }
}

// ============================================================
// PasswordHasher - Simple secure password hashing utility
// ============================================================
object PasswordHasher {
    fun hash(password: String): String {
        val bytes = java.security.MessageDigest.getInstance("SHA-256")
            .digest(password.toByteArray(Charsets.UTF_8))
        return bytes.joinToString("") { "%02x".format(it) }
    }

    fun verify(password: String, storedHash: String): Boolean {
        return hash(password) == storedHash
    }
}

// ============================================================
// BiometricHelper - Manages biometric prompt and authentication
// ============================================================
class BiometricHelper(
    private val activity: AppCompatActivity,
    private val onSuccess: () -> Unit,
    private val onError: (String) -> Unit,
    private val onFallbackToPassword: () -> Unit
) {

    private lateinit var executor: Executor
    private lateinit var biometricPrompt: BiometricPrompt
    private lateinit var promptInfo: BiometricPrompt.PromptInfo

    fun isBiometricAvailable(): Boolean {
        val biometricManager = BiometricManager.from(activity)
        return when (biometricManager.canAuthenticate(
            BiometricManager.Authenticators.BIOMETRIC_STRONG
        )) {
            BiometricManager.BIOMETRIC_SUCCESS -> true
            BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE -> false
            BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE -> false
            BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED -> false
            else -> false
        }
    }

    fun getBiometricStatusMessage(): String {
        val biometricManager = BiometricManager.from(activity)
        return when (biometricManager.canAuthenticate(
            BiometricManager.Authenticators.BIOMETRIC_STRONG
        )) {
            BiometricManager.BIOMETRIC_SUCCESS -> "Biometric authentication is available."
            BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE -> "No biometric hardware found on this device."
            BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE -> "Biometric hardware is currently unavailable."
            BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED -> "No biometric credentials enrolled. Please set up fingerprint in device settings."
            else -> "Biometric authentication is not available."
        }
    }

    fun authenticate() {
        executor = ContextCompat.getMainExecutor(activity)

        biometricPrompt = BiometricPrompt(activity, executor,
            object : BiometricPrompt.AuthenticationCallback() {

                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)
                    when (errorCode) {
                        BiometricPrompt.ERROR_NEGATIVE_BUTTON -> {
                            // User clicked "Use Password" button
                            onFallbackToPassword()
                        }
                        BiometricPrompt.ERROR_USER_CANCELED,
                        BiometricPrompt.ERROR_CANCELED -> {
                            onError("Authentication cancelled.")
                        }
                        BiometricPrompt.ERROR_LOCKOUT,
                        BiometricPrompt.ERROR_LOCKOUT_PERMANENT -> {
                            onError("Too many attempts. Please use your password instead.")
                            onFallbackToPassword()
                        }
                        else -> {
                            onError("Authentication error: $errString")
                        }
                    }
                }

                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)
                    onSuccess()
                }

                override fun onAuthenticationFailed() {
                    super.onAuthenticationFailed()
                    onError("Fingerprint not recognized. Please try again.")
                }
            })

        promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Biometric Login")
            .setSubtitle("Use your fingerprint to sign in")
            .setDescription("Place your finger on the sensor to verify your identity.")
            .setNegativeButtonText("Use Password")
            .setConfirmationRequired(true)
            .setAllowedAuthenticators(BiometricManager.Authenticators.BIOMETRIC_STRONG)
            .build()

        biometricPrompt.authenticate(promptInfo)
    }
}

