class LoginActivity : AppCompatActivity() {

    private lateinit var securePrefs: SecurePreferencesManager
    private lateinit var biometricHelper: BiometricHelper

    private lateinit var tvStatus: TextView
    private lateinit var etUsername: EditText
    private lateinit var etPassword: EditText
    private lateinit var btnLogin: Button
    private lateinit var btnBiometric: Button
    private lateinit var passwordContainer: View

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        securePrefs = SecurePreferencesManager(this)

        // Check if already authenticated - bypass login
        if (securePrefs.isAuthenticated() && securePrefs.getSessionToken() != null) {
            navigateToMain()
            return
        }

        setContentView(R.layout.activity_login)

        initViews()
        initBiometricHelper()
        setupUI()
    }

    private fun initViews() {
        tvStatus = findViewById(R.id.tvStatus)
        etUsername = findViewById(R.id.etUsername)
        etPassword = findViewById(R.id.etPassword)
        btnLogin = findViewById(R.id.btnLogin)
        btnBiometric = findViewById(R.id.btnBiometric)
        passwordContainer = findViewById(R.id.passwordContainer)
    }

    private fun initBiometricHelper() {
        biometricHelper = BiometricHelper(
            activity = this,
            onSuccess = {
                onBiometricSuccess()
            },
            onError = { message ->
                tvStatus.text = message
                tvStatus.visibility = View.VISIBLE
            },
            onFallbackToPassword = {
                showPasswordLogin()
            }
        )
    }

    private fun setupUI() {
        // If biometric is available and was previously enabled, show biometric option
        if (biometricHelper.isBiometricAvailable() && securePrefs.isBiometricEnabled()) {
            btnBiometric.visibility = View.VISIBLE
            passwordContainer.visibility = View.GONE
            tvStatus.text = "Tap the button below to sign in with your fingerprint"
            tvStatus.visibility = View.VISIBLE

            // Auto-trigger biometric prompt
            biometricHelper.authenticate()
        } else if (biometricHelper.isBiometricAvailable()) {
            // Biometric available but not yet enabled - show password login first
            btnBiometric.visibility = View.GONE
            passwordContainer.visibility = View.VISIBLE
            tvStatus.text = "Sign in to enable biometric authentication"
            tvStatus.visibility = View.VISIBLE
        } else {
            // No biometric available
            btnBiometric.visibility = View.GONE
            passwordContainer.visibility = View.VISIBLE
            tvStatus.text = biometricHelper.getBiometricStatusMessage()
            tvStatus.visibility = View.VISIBLE
        }

        btnBiometric.setOnClickListener {
            biometricHelper.authenticate()
        }

        btnLogin.setOnClickListener {
            handlePasswordLogin()
        }
    }

    private fun showPasswordLogin() {
        passwordContainer.visibility = View.VISIBLE
        tvStatus.text = "Please sign in with your password"
        tvStatus.visibility = View.VISIBLE
    }

    private fun handlePasswordLogin() {
        val username = etUsername.text.toString().trim()
        val password = etPassword.text.toString()

        if (username.isEmpty() || password.isEmpty()) {
            tvStatus.text = "Please enter both username and password."
            tvStatus.visibility = View.VISIBLE
            return
        }

        // Validate password length
        if (password.length < 8) {
            tvStatus.text = "Password must be at least 8 characters."
            tvStatus.visibility = View.VISIBLE
            return
        }

        // Check stored credentials or perform server authentication
        val storedHash = securePrefs.getPasswordHash()
        if (storedHash != null) {
            // Existing user - verify password
            if (PasswordHasher.verify(password, storedHash)) {
                onPasswordLoginSuccess(username)
            } else {
                tvStatus.text = "Invalid credentials. Please try again."
                tvStatus.visibility = View.VISIBLE
                // Clear password field for security
                etPassword.text.clear()
            }
        } else {
            // First time login - store credentials (in production, verify with server first)
            securePrefs.setPasswordHash(PasswordHasher.hash(password))
            onPasswordLoginSuccess(username)
        }
    }

    private fun onPasswordLoginSuccess(username: String) {
        // Generate a session token (in production, this comes from your server)
        val sessionToken = generateSessionToken()
        securePrefs.setSessionToken(sessionToken)
        securePrefs.setAuthenticated(true)

        // Offer to enable biometric if available
        if (biometricHelper.isBiometricAvailable() && !securePrefs.isBiometricEnabled()) {
            showEnableBiometricDialog()
        } else {
            navigateToMain()
        }
    }

    private fun onBiometricSuccess() {
        securePrefs.setAuthenticated(true)
        tvStatus.text = "Authentication successful!"
        tvStatus.visibility = View.VISIBLE

        Toast.makeText(this, "Welcome back!", Toast.LENGTH_SHORT).show()
        navigateToMain()
    }

    private fun showEnableBiometricDialog() {
        androidx.appcompat.app.AlertDialog.Builder(this)
            .setTitle("Enable Biometric Login")
            .setMessage("Would you like to use your fingerprint for faster sign-in next time?")
            .setPositiveButton("Enable") { _, _ ->
                securePrefs.setBiometricEnabled(true)
                Toast.makeText(this, "Biometric login enabled!", Toast.LENGTH_SHORT).show()
                navigateToMain()
            }
            .setNegativeButton("Not Now") { dialog, _ ->
                dialog.dismiss()
                navigateToMain()
            }
            .setCancelable(false)
            .show()
    }

    private fun navigateToMain() {
        val intent = Intent(this, MainActivity::class.java)
        intent.flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
        startActivity(intent)
        finish()
    }

    private fun generateSessionToken(): String {
        val bytes = ByteArray(32)
        java.security.SecureRandom().nextBytes(bytes)
        return bytes.joinToString("") { "%02x".format(it) }
    }
}

// ============================================================
// MainActivity - The main screen after successful authentication
// ============================================================
class MainActivity : AppCompatActivity() {

    private lateinit var securePrefs: SecurePreferencesManager

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        securePrefs = SecurePreferencesManager(this)

        // Verify authentication
        if (!securePrefs.isAuthenticated() || securePrefs.getSessionToken() == null) {
            redirectToLogin()
            return
        }

        setContentView(R.layout.activity_main)

        val tvWelcome: TextView = findViewById(R.id.tvWelcome)
        val btnLogout: Button = findViewById(R.id.btnLogout)
        val btnToggleBiometric: Button = findViewById(R.id.btnToggleBiometric)

        tvWelcome.text = "Welcome! You are securely authenticated."

        val biometricHelper = BiometricHelper(
            activity = this,
            onSuccess = {},
            onError = {},
            onFallbackToPassword = {}
        )

        if (biometricHelper.isBiometricAvailable()) {
            btnToggleBiometric.visibility = View.VISIBLE
            updateBiometricButtonText(btnToggleBiometric)

            btnToggleBiometric.setOnClickListener {
                val currentState = securePrefs.isBiometricEnabled()
                securePrefs.setBiometricEnabled(!currentState)
                updateBiometricButtonText(btnToggleBiometric)

                val message = if (!currentState) {
                    "Biometric login enabled"
                } else {
                    "Biometric login disabled"
                }
                Toast.makeText(this, message, Toast.LENGTH_SHORT).show()
            }
        } else {
            btnToggleBiometric.visibility = View.GONE
        }

        btnLogout.setOnClickListener {
            logout()
        }
    }

    private fun updateBiometricButtonText(button: Button) {
        button.text = if (securePrefs.isBiometricEnabled()) {
            "Disable Biometric Login"
        } else {
            "Enable Biometric Login"
        }
    }

    private fun logout() {
        // Keep biometric preference but clear session
        val biometricEnabled = securePrefs.isBiometricEnabled()
        val passwordHash = securePrefs.getPasswordHash()

        securePrefs.setAuthenticated(false)
        securePrefs.setSessionToken("")

        // Restore preferences that should persist across sessions
        securePrefs.setBiometricEnabled(biometricEnabled)
        if (passwordHash != null) {
            securePrefs.setPasswordHash(passwordHash)
        }

        redirectToLogin()
    }

    private fun redirectToLogin() {
        val intent = Intent(this, LoginActivity::class.java)
        intent.flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
        startActivity(intent)
        finish()
    }
}